from sage.all_cmdline import *   # import sage library

_sage_const_1 = Integer(1); _sage_const_0 = Integer(0); _sage_const_2 = Integer(2); _sage_const_5 = Integer(5)# ---------------------------------------------------------
# SageMath: [ψ_μ, ψ_ν]_+ = 0 (coefficient = 0 with ν=-μ)
# 対象: parts/008_.../031_claim_psiの反交換関係.typ Claim c)
#
# coefficient = c_μ c_ν * (-sqrt(γγ-)_μ sqrt(γγ-)_ν + γ_(-θ_μ) γ_(-θ_ν)) * 2M
# (a) と同じ式。ν = -μ のとき coefficient = 0
