import os
_dir = os.path.dirname(os.path.abspath(__file__)) if '__file__' in dir() else '.'
load(os.path.join(_dir, '../../_shared/defs.sage'))

print("\n--- Numerical Verification: [ψ_μ, ψ_ν]_+ = 0 (with ν=-μ) ---")

test_params = DEFAULT_TEST_PARAMS
M_val = DEFAULT_M_VAL
tol = DEFAULT_TOLERANCE

all_ok = True

for params in test_params:
    val_K1 = params['K1']
    val_K2 = params['K2']
    print(f"Parameters: K1={val_K1}, K2={val_K2}, M={M_val}")

    mu_list = [m for m in range(-M_val, M_val + _sage_const_1 ) if m != _sage_const_0 ]
    fail_count = _sage_const_0 

    for mu in mu_list:
        th_mu = (_sage_const_2  * pi * mu) / M_val
        nu = -mu
        th_nu = (_sage_const_2  * pi * nu) / M_val

        subs_dict = {K1: val_K1, K2: val_K2}

        g2_mu_pos = CC(gamma_2(th_mu).subs(subs_dict))
        g2_mu_neg = CC(gamma_2(-th_mu).subs(subs_dict))
        g2_nu_pos = CC(gamma_2(th_nu).subs(subs_dict))
        g2_nu_neg = CC(gamma_2(-th_nu).subs(subs_dict))

        sqrt_mu = sqrt_cc(g2_mu_pos * g2_mu_neg)
        sqrt_nu = sqrt_cc(g2_nu_pos * g2_nu_neg)

        c_mu = _sage_const_1  / (_sage_const_2  * CC(sqrt(M_val)) * g2_mu_neg)
        c_nu = _sage_const_1  / (_sage_const_2  * CC(sqrt(M_val)) * g2_nu_neg)

        coeff = c_mu * c_nu * (-sqrt_mu * sqrt_nu + g2_mu_neg * g2_nu_neg) * _sage_const_2  * M_val

        err = abs(coeff)
        if err > tol:
            if fail_count < _sage_const_5 :
                print(f"  MISMATCH at mu={mu}: |coeff| = {err}, coeff = {coeff}")
            fail_count += _sage_const_1 
            all_ok = False

    if fail_count > _sage_const_5 :
        print(f"  ... and {fail_count - _sage_const_5 } more mismatches")

if all_ok:
    print("RESULT: PASS")
else:
    print("RESULT: FAIL")

